const raw = $input.first().json;
const data = (raw.body && typeof raw.body === 'object') ? raw.body : raw;

const nombre   = data.nombre   || '';
const negocio  = data.negocio  || '';
const telefono = data.telefono || '';
const email    = data.email    || '';
