const keywords = ['mantenimiento','soporte','mensual','actualizaciones','gestionar','cambios mensuales'];
const esMantenimiento = keywords.some(k => msg.includes(k));

const planNombre  = esMantenimiento ? 'Lanzamiento + Mantenimiento' : 'Lanzamiento';
const planPrecio  = esMantenimiento ? '300\u20ac + 50\u20ac/mes' : '300\u20ac (pago \u00fanico)';
const planFeatures = esMantenimiento
  ? '\u2713 Todo lo del plan Lanzamiento \u00b7 \u2713 Actualizaciones y cambios mensuales \u00b7 \u2713 Soporte prioritario ilimitado \u00b7 \u2713 Copia de seguridad mensual \u00b7 \u2713 Monitorizaci\u00f3n de disponibilidad \u00b7 \u2713 Optimizaci\u00f3n continua de conversi\u00f3n'
  : '\u2713 Tienda Shopify profesional completa \u00b7 \u2713 Dise\u00f1o personalizado a su marca \u00b7 \u2713 Hasta 30 productos cargados \u00b7 \u2713 Pagos, env\u00edos y dominio configurados \u00b7 \u2713 SEO local activado \u00b7 \u2713 15 d\u00edas de soporte post-lanzamiento';

// URL WhatsApp con mensaje preescrito
const waMsg = 'Hola Woodia! Soy ' + nombre + ' de ' + negocio + '. Acabo de recibir la info del plan ' + planNombre + ' y me gustar\u00eda empezar.';
const whatsappUrl = 'https://wa.me/34624594551?text=' + encodeURIComponent(waMsg);

// HTML del email (inline CSS — compatible con Gmail)
const emailHtml = '<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width"></head>'
  + '<body style="margin:0;padding:0;background-color:#f5f3ef;font-family:\'Helvetica Neue\',Arial,sans-serif;">'
  + '<table width="100%" cellpadding="0" cellspacing="0" style="background-color:#f5f3ef;padding:32px 16px;"><tr><td align="center">'
  + '<table width="600" cellpadding="0" cellspacing="0" style="background-color:#ffffff;border-radius:12px;overflow:hidden;box-shadow:0 4px 24px rgba(0,0,0,0.08);">'

  // HEADER
  + '<tr><td style="background-color:#0d0d0d;padding:32px 40px;text-align:center;">'
  + '<p style="margin:0;font-size:22px;font-weight:800;color:#ffffff;letter-spacing:-0.5px;">Woodia Spain</p>'
  + '<p style="margin:6px 0 0;font-size:12px;color:#c8a951;text-transform:uppercase;letter-spacing:2px;">Tiendas Shopify profesionales</p>'
  + '</td></tr>'

  // BODY
  + '<tr><td style="padding:40px;">'
  + '<p style="margin:0 0 8px;font-size:13px;color:#c8a951;font-weight:700;text-transform:uppercase;letter-spacing:1.5px;">Gracias por contactarnos</p>'
  + '<h1 style="margin:0 0 20px;font-size:26px;font-weight:800;color:#0d0d0d;line-height:1.2;">Hola ' + nombre + ', \u00a1bienvenido/a!</h1>'
  + '<p style="margin:0 0 24px;font-size:15px;color:#555;line-height:1.7;">Hemos recibido su solicitud para <strong style="color:#0d0d0d;">' + negocio + '</strong>. Hemos analizado lo que necesita y creemos que el plan ideal para su proyecto es:</p>'

