  + '<p style="margin:0 0 4px;font-size:13px;color:#6b6660;">\u00a9 2026 Woodia Spain \u00b7 A Coru\u00f1a, Galicia</p>'
  + '<p style="margin:0;font-size:12px;color:#999;">Este email se ha enviado porque solicit\u00f3 informaci\u00f3n en woodiaspain.com</p>'
  + '</td></tr>'

  + '</table></td></tr></table></body></html>';

// Asunto personalizado
