  + '<tr><td style="padding:8px;border:1px solid #ddd;font-weight:bold;">Nombre</td><td style="padding:8px;border:1px solid #ddd;">' + nombre + '</td></tr>'
  + '<tr><td style="padding:8px;border:1px solid #ddd;font-weight:bold;">Negocio</td><td style="padding:8px;border:1px solid #ddd;">' + negocio + '</td></tr>'
  + '<tr><td style="padding:8px;border:1px solid #ddd;font-weight:bold;">Tel\u00e9fono</td><td style="padding:8px;border:1px solid #ddd;">' + telefono + '</td></tr>'
  + '<tr><td style="padding:8px;border:1px solid #ddd;font-weight:bold;">Email</td><td style="padding:8px;border:1px solid #ddd;">' + email + '</td></tr>'
  + '<tr><td style="padding:8px;border:1px solid #ddd;font-weight:bold;">Mensaje</td><td style="padding:8px;border:1px solid #ddd;">' + mensaje + '</td></tr>'
  + '<tr><td style="padding:8px;border:1px solid #ddd;font-weight:bold;">Plan recomendado</td><td style="padding:8px;border:1px solid #c8a951;color:#c8a951;font-weight:bold;">' + planNombre + ' — ' + planPrecio + '</td></tr>'
  + '<tr><td style="padding:8px;border:1px solid #ddd;font-weight:bold;">Fecha</td><td style="padding:8px;border:1px solid #ddd;">' + fecha + '</td></tr>'
  + '</table>'
  + '<br><a href="' + whatsappUrl + '" style="background:#25D366;color:white;padding:10px 20px;text-decoration:none;border-radius:6px;font-family:Arial,sans-serif;">Responder por WhatsApp</a>';

return [{
  json: {
    nombre, negocio, telefono, email, mensaje, fecha,
    plan_nombre: planNombre,
    plan_precio: planPrecio,
    plan_features: planFeatures,
    whatsapp_url: whatsappUrl,
    subject,
    email_html: emailHtml,
    internal_html: internalHtml
  }
